using BenchmarkDotNet.Attributes;
using BenchmarkDotNet.Configs;
using BenchmarkDotNet.Jobs;
using BenchmarkDotNet.Running;
using TextAnalysis;

BenchmarkRunner.Run<TextAnalyzerBenchmarks>();

[MemoryDiagnoser]
[SimpleJob(RuntimeMoniker.Net90)]
[SimpleJob(RuntimeMoniker.Net100)]
public class TextAnalyzerBenchmarks
{
    private TextAnalyzer _analyzer = null!;

    [GlobalSetup]
    public void Setup()
    {
        // Build a representative text corpus (~1000 words)
        var words = new string[]
        {
            "the", "quick", "brown", "fox", "jumps", "over", "the", "lazy", "dog",
            "and", "then", "runs", "back", "to", "its", "den", "where", "it",
            "rests", "until", "morning", "comes", "with", "bright", "sunshine",
            "performance", "benchmarking", "optimization", "throughput", "latency",
            "infrastructure", "development", "engineering", "architecture", "software"
        };

        var rng = new Random(42);
        var sb = new System.Text.StringBuilder();
        for (int i = 0; i < 1000; i++)
        {
            if (i > 0) sb.Append(' ');
            sb.Append(words[rng.Next(words.Length)]);
        }

        _analyzer = new TextAnalyzer(sb.ToString());
    }

    [Benchmark]
    public double AverageWordLength() => _analyzer.AverageWordLength();

    [Benchmark]
    public object WordLengthHistogram() => _analyzer.WordLengthHistogram();

    [Benchmark]
    public int UniqueWordCount() => _analyzer.UniqueWordCount();
}

