var sb = new System.Text.StringBuilder();
for (int i = 0; i < 1000; i++)
{
    if (i > 0) sb.Append(' ');
    sb.Append(words[rng.Next(words.Length)]);
}

var analyzer = new TextAnalyzer(sb.ToString());

Console.WriteLine($"Runtime: {RuntimeInformation.FrameworkDescription}");
Console.WriteLine($"Words: {analyzer.WordCount}");
Console.WriteLine();

// Warmup + benchmark helper
static (double medianNs, double minNs, double maxNs) Benchmark(Action action, int warmup = 500, int iterations = 20, int opsPerIteration = 10_000)
{
    // Warmup
    for (int i = 0; i < warmup; i++)
        action();

    var timings = new double[iterations];
    for (int iter = 0; iter < iterations; iter++)
    {
        // Force GC between iterations for consistency
        GC.Collect();
        GC.WaitForPendingFinalizers();
        GC.Collect();

        var sw = Stopwatch.StartNew();
        for (int i = 0; i < opsPerIteration; i++)
            action();
        sw.Stop();

        timings[iter] = (double)sw.ElapsedTicks / Stopwatch.Frequency * 1e9 / opsPerIteration;
    }

    Array.Sort(timings);
    double median = timings[iterations / 2];
    return (median, timings[0], timings[^1]);
}

